        val sb = StringBuilder(length)
        for (i in 0 until length) {
            val index = secureRandom.nextInt(ALPHANUMERIC_CHARS.length)
            sb.append(ALPHANUMERIC_CHARS[index])
        }
        return sb.toString()
    }

    fun startSession(durationMs: Long = DEFAULT_SESSION_DURATION_MS): String {
        val now = System.currentTimeMillis()
        currentSessionId = generateRandomString(SESSION_ID_LENGTH)
