    }

    fun getApiRequestTokenWithCustomDuration(durationMs: Long): SessionToken? {
        return tokenGenerator.generateTemporaryToken(durationMs)
    }

    fun validateApiToken(token: String): Boolean {
        return tokenGenerator.validateTemporaryToken(token)
    }

    fun onApiRequestCompleted(token: String) {
        tokenGenerator.invalidateTemporaryToken(token)
    }

    fun onAppClosed() {
        tokenGenerator.endSession()
    }

    fun keepSessionAlive() {
        tokenGenerator.renewSession()
    }

    fun isUserSessionActive(): Boolean {
        return tokenGenerator.isSessionValid()
    }

    fun getSessionDetails(): Map<String, Any?> {
        return tokenGenerator.getSessionInfo()
    }
}

